<script setup lang="ts">import{ref}from'vue';import{useRouter}from'vue-router';import{api}from'../api/client';const router=useRouter();const file=ref<File>();const progress=ref(0);const loading=ref(false);const error=ref('');function choose(e:Event){file.value=(e.target as HTMLInputElement).files?.[0]}async function upload(){if(!file.value)return;loading.value=true;error.value='';const form=new FormData();form.append('file',file.value);try{const{data}=await api.post('/imports',form,{onUploadProgress:e=>progress.value=e.total?Math.round(e.loaded/e.total*100):0});await router.push(`/books/${data.book.id}`)}catch(e:any){error.value=e.response?.data?.error||'上传失败'}finally{loading.value=false}}</script>
<template><section><el-page-header @back="$router.push('/')" title="返回书库"/><el-card><h1>上传书籍</h1><p>支持 EPUB、PDF、MOBI、AZW3 和 TXT。EPUB/PDF 会自动读取基础元数据。</p><input type="file" accept=".epub,.pdf,.mobi,.azw3,.txt" @change="choose"/><el-progress v-if="loading" :percentage="progress"/><el-alert v-if="error" :title="error" type="error" show-icon/><el-button type="primary" :disabled="!file" :loading="loading" @click="upload">开始上传</el-button></el-card></section></template>
<style scoped>.el-card{max-width:600px;margin:2rem auto}.el-card>*{margin-bottom:1rem}input{display:block}</style>
